def permission_callback(tool_call):
    # Check if tool is allowed
    if tool_call.tool_name == "write_file":
        # Only allow writing to safe directories
        if not tool_call.path.startswith("/safe/"):
            raise ValueError("Only write to safe directories")
    return True  # Allow

